    mount_reason = str(mount_health.get("reason") or "").strip()
    if mount_status == "RED":
        reasons.append(f"data_mount_health=RED:{mount_reason or 'mount_unhealthy'}")
    elif mount_status == "YELLOW":
        warnings.append(f"data_mount_health=YELLOW:{mount_reason or 'fallback_in_use'}")
    for item in (mount_health.get("warnings") or []):
        text = str(item).strip()
        if text:
            warnings.append(f"mount_warning:{text}")

    if strict_precheck:
        passed = len(reasons) == 0
    else:
        passed = True
    return PrecheckResult(passed=passed, reasons=reasons, warnings=warnings)

